INSERT INTO "CompanyInfo" ("id", "name", "taglineEn", "taglineAr", "storyEn", "storyAr", "missionEn", "missionAr", "visionEn", "visionAr", "valuesEn", "valuesAr", "registrationNo", "licenseInfo", "addressEn", "addressAr", "phone", "whatsapp", "email", "officeHoursEn", "officeHoursAr", "socialLinks", "trustBadges", "updatedAt") VALUES ('default', 'BRT TRADING LLC', 'Innovative Wireless & Smart Technology Solutions', 'حلول لاسلكية وتقنية ذكية مبتكرة', 'BRT TRADING LLC is a leading provider of wireless communication, networking, security, and smart automation solutions. With over a decade of industry experience, we help organizations and homeowners leverage cutting-edge technologies to improve connectivity, security, operational efficiency, and digital transformation.', 'شركة BRT TRADING LLC هي مزود رائد لحلول الاتصالات اللاسلكية والشبكات والأمن والأتمتة الذكية. بخبرة تزيد عن عقد في المجال، نساعد المؤسسات وأصحاب المنازل على الاستفادة من أحدث التقنيات لتحسين الاتصال والأمن والكفاءة التشغيلية.', 'Deliver reliable, scalable, and future-ready technology solutions that enhance connectivity, improve security, and create smarter living and working environments.', 'تقديم حلول تقنية موثوقة وقابلة للتوسع وجاهزة للمستقبل تعزز الاتصال وتحسن الأمن وتخلق بيئات معيشة وعمل أكثر ذكاءً.', 'Empowering connectivity, enhancing security, and enabling smart living across enterprises and homes throughout the region.', 'تمكين الاتصال وتعزيز الأمن وتمكين المعيشة الذكية عبر المؤسسات والمنازل في المنطقة.', '["Quality","Innovation","Customer Satisfaction"]'::jsonb, '["الجودة","الابتكار","رضا العملاء"]'::jsonb, 'BRT-2024-UAE', 'Licensed technology solutions provider — UAE', 'Dubai, United Arab Emirates', 'دبي، الإمارات العربية المتحدة', '+971 55 472 7292', '+971554727292', 'info@brt-me.com', 'Sun–Thu: 9:00 AM – 6:00 PM', 'الأحد–الخميس: 9:00 ص – 6:00 م', '{"facebook":"https://facebook.com","linkedin":"https://linkedin.com","instagram":"https://instagram.com"}'::jsonb, '[{"icon":"fa-award","labelAr":"أكثر من 10 سنوات خبرة","labelEn":"10+ Years Experience"},{"icon":"fa-briefcase","labelAr":"أكثر من 500 مشروع","labelEn":"500+ Projects Delivered"},{"icon":"fa-star","labelAr":"99% رضا العملاء","labelEn":"99% Client Satisfaction"},{"icon":"fa-certificate","labelAr":"خبرة معتمدة","labelEn":"Certified Expertise"}]'::jsonb, '2026-06-05 11:01:42.305'::timestamp(3));
