INSERT INTO "FaqItem" ("id", "faqSetId", "questionEn", "questionAr", "answerEn", "answerAr", "sortOrder", "isPublished", "createdAt", "updatedAt") VALUES ('cmq0tdrv6000khf64t7m4n8uk', 'cmq0tdrv6000jhf644uswq4dj', 'What industries does BRT TRADING LLC serve?', 'ما القطاعات التي تخدمها BRT TRADING LLC؟', 'We serve enterprises, commercial facilities, hospitality, residential developments, and government sectors with wireless, security, and smart technology solutions.', 'نخدم المؤسسات والمرافق التجارية والضيافة والتطويرات السكنية والقطاع الحكومي بحلول لاسلكية وأمنية وتقنية ذكية.', 0, true, '2026-06-05 11:01:42.354'::timestamp(3), '2026-06-05 11:01:42.354'::timestamp(3));
INSERT INTO "FaqItem" ("id", "faqSetId", "questionEn", "questionAr", "answerEn", "answerAr", "sortOrder", "isPublished", "createdAt", "updatedAt") VALUES ('cmq0tdrv6000lhf64ho27or6v', 'cmq0tdrv6000jhf644uswq4dj', 'Do you provide ongoing support after installation?', 'هل تقدمون دعماً مستمراً بعد التركيب؟', 'Yes. We offer continuous monitoring, technical support, upgrades, and optimization services to keep systems performing at their best.', 'نعم. نقدم مراقبة مستمرة ودعماً فنياً وترقيات وخدمات تحسين لضمان أداء الأنظمة بأفضل حال.', 1, true, '2026-06-05 11:01:42.354'::timestamp(3), '2026-06-05 11:01:42.354'::timestamp(3));
INSERT INTO "FaqItem" ("id", "faqSetId", "questionEn", "questionAr", "answerEn", "answerAr", "sortOrder", "isPublished", "createdAt", "updatedAt") VALUES ('cmq0tdrv6000mhf64sots1nse', 'cmq0tdrv6000jhf644uswq4dj', 'How long does a typical project take?', 'كم تستغرق المشاريع عادةً؟', 'Project timelines vary by scope. A site survey and consultation typically lead to a detailed timeline during the design phase.', 'تختلف الجداول الزمنية حسب نطاق المشروع. عادةً يتم تحديد جدول مفصل خلال مرحلة التصميم بعد المعاينة.', 2, true, '2026-06-05 11:01:42.354'::timestamp(3), '2026-06-05 11:01:42.354'::timestamp(3));
INSERT INTO "FaqItem" ("id", "faqSetId", "questionEn", "questionAr", "answerEn", "answerAr", "sortOrder", "isPublished", "createdAt", "updatedAt") VALUES ('cmq0tdrvd000ohf64h7nwqq9t', 'cmq0tdrvd000nhf64pzu1d682', 'Which voice assistants are supported?', 'ما المساعدات الصوتية المدعومة؟', 'Our smart home solutions integrate with Amazon Alexa, Google Assistant, and Apple Siri.', 'تتكامل حلول المنزل الذكي مع Amazon Alexa وGoogle Assistant وApple Siri.', 0, true, '2026-06-05 11:01:42.361'::timestamp(3), '2026-06-05 11:01:42.361'::timestamp(3));
INSERT INTO "FaqItem" ("id", "faqSetId", "questionEn", "questionAr", "answerEn", "answerAr", "sortOrder", "isPublished", "createdAt", "updatedAt") VALUES ('cmq0tdrvd000phf64vm9nrz5r', 'cmq0tdrvd000nhf64pzu1d682', 'Can I control my home remotely?', 'هل يمكنني التحكم في منزلي عن بُعد؟', 'Yes. Monitor and manage lighting, climate, security, and devices from your smartphone, tablet, or voice commands.', 'نعم. راقب وأدر الإضاءة والمناخ والأمن والأجهزة من هاتفك أو جهازك اللوحي أو الأوامر الصوتية.', 1, true, '2026-06-05 11:01:42.361'::timestamp(3), '2026-06-05 11:01:42.361'::timestamp(3));
INSERT INTO "FaqItem" ("id", "faqSetId", "questionEn", "questionAr", "answerEn", "answerAr", "sortOrder", "isPublished", "createdAt", "updatedAt") VALUES ('cmq0tdrvg000rhf647lslusoc', 'cmq0tdrvg000qhf648rfl3owb', 'What security systems do you install?', 'ما أنظمة الأمن التي تركبونها؟', 'CCTV surveillance, access control, smart locks, video analytics, motion detection, and integrated security platforms.', 'أنظمة CCTV والتحكم في الوصول والأقفال الذكية وتحليلات الفيديو وكشف الحركة ومنصات أمن متكاملة.', 0, true, '2026-06-05 11:01:42.364'::timestamp(3), '2026-06-05 11:01:42.364'::timestamp(3));
