INSERT INTO "Post" ("id", "slug", "titleEn", "titleAr", "excerptEn", "excerptAr", "contentEn", "contentAr", "blocks", "relatedPostIds", "status", "featuredImageId", "authorId", "publishedAt", "scheduledAt", "createdAt", "updatedAt") VALUES ('cmq0tdrxr002hhf643sqmuivb', 'iot-trends-2026', 'IoT Trends Shaping Smart Buildings in 2026', 'اتجاهات إنترنت الأشياء في المباني الذكية 2026', 'How connected devices are transforming facility management and energy efficiency.', 'كيف تحول الأجهزة المتصلة إدارة المرافق وكفاءة الطاقة.', '<p>The Internet of Things continues to revolutionize how buildings operate. From predictive maintenance to real-time energy monitoring, IoT solutions deliver measurable ROI for enterprises.</p><p>BRT TRADING LLC helps organizations integrate devices, automate processes, and gain valuable insights through intelligent control systems.</p>', '<p>يستمر إنترنت الأشياء في إحداث ثورة في تشغيل المباني. من الصيانة التنبؤية إلى مراقبة الطاقة الفورية، تقدم حلول IoT عائداً استثمارياً ملموساً للمؤسسات.</p>', '[]'::jsonb, '[]'::jsonb, 'PUBLISHED', 'cmq0tdrun0006hf64h0stiwnr', 'cmq0tdrxo002fhf64ucvpvoji', '2026-06-05 11:01:42.432'::timestamp(3), NULL, '2026-06-05 11:01:42.447'::timestamp(3), '2026-06-05 11:01:42.447'::timestamp(3));
INSERT INTO "Post" ("id", "slug", "titleEn", "titleAr", "excerptEn", "excerptAr", "contentEn", "contentAr", "blocks", "relatedPostIds", "status", "featuredImageId", "authorId", "publishedAt", "scheduledAt", "createdAt", "updatedAt") VALUES ('cmq0tdrxv002jhf648v08san5', 'smart-home-security-guide', 'Smart Home Security: A Complete Guide', 'أمن المنزل الذكي: دليل شامل', 'Protect your property with integrated smart locks, cameras, and automated responses.', 'احمِ ممتلكاتك بأقفال ذكية وكاميرات واستجابات آلية متكاملة.', '<p>Smart security goes beyond traditional alarms. With intelligent surveillance, motion detection, and automated response systems, homeowners gain peace of mind and instant alerts.</p>', '<p>الأمن الذكي يتجاوز الإنذارات التقليدية. مع المراقبة الذكية وكشف الحركة والاستجابات الآلية، يحصل أصحاب المنازل على راحة البال.</p>', '[]'::jsonb, '[]'::jsonb, 'PUBLISHED', 'cmq0tdrum0005hf64vsdbr5q0', 'cmq0tdrxo002fhf64ucvpvoji', '2026-06-05 11:01:42.436'::timestamp(3), NULL, '2026-06-05 11:01:42.451'::timestamp(3), '2026-06-05 11:01:42.451'::timestamp(3));
INSERT INTO "Post" ("id", "slug", "titleEn", "titleAr", "excerptEn", "excerptAr", "contentEn", "contentAr", "blocks", "relatedPostIds", "status", "featuredImageId", "authorId", "publishedAt", "scheduledAt", "createdAt", "updatedAt") VALUES ('cmq0tdry0002lhf64b3bc8mks', 'enterprise-wifi-best-practices', 'Enterprise Wi-Fi Best Practices', 'أفضل ممارسات Wi-Fi للمؤسسات', 'Design principles for reliable, high-performance wireless networks.', 'مبادئ تصميم شبكات لاسلكية موثوقة وعالية الأداء.', '<p>Enterprise wireless networks require careful planning. Site surveys, coverage analysis, and ongoing optimization ensure maximum stability and performance across your facility.</p>', '<p>تتطلب الشبكات اللاسلكية للمؤسسات تخطيطاً دقيقاً. المعاينات وتحليل التغطية والتحسين المستمر يضمن أقصى استقرار وأداء.</p>', '[]'::jsonb, '[]'::jsonb, 'PUBLISHED', 'cmq0tdruz000fhf64iuz3dr62', 'cmq0tdrxo002fhf64ucvpvoji', '2026-06-05 11:01:42.441'::timestamp(3), NULL, '2026-06-05 11:01:42.456'::timestamp(3), '2026-06-05 11:01:42.456'::timestamp(3));
INSERT INTO "Post" ("id", "slug", "titleEn", "titleAr", "excerptEn", "excerptAr", "contentEn", "contentAr", "blocks", "relatedPostIds", "status", "featuredImageId", "authorId", "publishedAt", "scheduledAt", "createdAt", "updatedAt") VALUES ('cmq0tdry2002nhf64yujo4i0d', 'energy-efficiency-smart-tech', 'Energy Efficiency Through Smart Technology', 'كفاءة الطاقة عبر التقنية الذكية', 'Reduce energy costs by up to 30% with intelligent scheduling and automation.', 'قلل تكاليف الطاقة بنسبة تصل إلى 30% عبر الجدولة الذكية والأتمتة.', '<p>Smart technologies help reduce energy consumption while improving comfort. Automated monitoring, intelligent scheduling, and 24/7 energy analytics deliver sustainable building management.</p>', '<p>تساعد التقنيات الذكية على تقليل استهلاك الطاقة مع تحسين الراحة. المراقبة الآلية والجدولة الذكية تحقق إدارة مباني مستدامة.</p>', '[]'::jsonb, '[]'::jsonb, 'PUBLISHED', 'cmq0tdrux000ehf64744jlrnl', 'cmq0tdrxo002fhf64ucvpvoji', '2026-06-05 11:01:42.443'::timestamp(3), NULL, '2026-06-05 11:01:42.458'::timestamp(3), '2026-06-05 11:01:42.458'::timestamp(3));
