INSERT INTO "Testimonial" ("id", "name", "location", "rating", "contentEn", "contentAr", "videoUrl", "imageUrl", "isPublished", "sortOrder", "createdAt", "updatedAt") VALUES ('cmq0tdrvi000shf640c8v3nu1', 'Ahmed Al-Rashid', 'Dubai, UAE', 5, 'BRT delivered a flawless enterprise wireless network for our headquarters. Coverage is excellent and support is responsive.', 'قدمت BRT شبكة لاسلكية ممتازة لمقرنا. التغطية رائعة والدعم سريع الاستجابة.', NULL, '', true, 0, '2026-06-05 11:01:42.366'::timestamp(3), '2026-06-05 11:01:42.366'::timestamp(3));
INSERT INTO "Testimonial" ("id", "name", "location", "rating", "contentEn", "contentAr", "videoUrl", "imageUrl", "isPublished", "sortOrder", "createdAt", "updatedAt") VALUES ('cmq0tdrvl000thf64ctnbms3j', 'Sarah Mitchell', 'Abu Dhabi, UAE', 5, 'Our smart home automation project exceeded expectations. Everything works seamlessly with voice control.', 'مشروع أتمتة منزلنا الذكي فاق التوقعات. كل شيء يعمل بسلاسة مع التحكم الصوتي.', NULL, '', true, 1, '2026-06-05 11:01:42.369'::timestamp(3), '2026-06-05 11:01:42.369'::timestamp(3));
INSERT INTO "Testimonial" ("id", "name", "location", "rating", "contentEn", "contentAr", "videoUrl", "imageUrl", "isPublished", "sortOrder", "createdAt", "updatedAt") VALUES ('cmq0tdrvm000uhf643ji7rije', 'Khalid Hassan', 'Sharjah, UAE', 5, 'Professional security installation with intelligent monitoring. We feel much safer with BRT''s integrated system.', 'تركيب أمني احترافي مع مراقبة ذكية. نشعر بأمان أكبر مع النظام المتكامل من BRT.', NULL, '', true, 2, '2026-06-05 11:01:42.370'::timestamp(3), '2026-06-05 11:01:42.370'::timestamp(3));
INSERT INTO "Testimonial" ("id", "name", "location", "rating", "contentEn", "contentAr", "videoUrl", "imageUrl", "isPublished", "sortOrder", "createdAt", "updatedAt") VALUES ('cmq0tdrvm000vhf642fzf3quo', 'Jennifer Park', 'Dubai, UAE', 5, 'Indoor coverage solutions eliminated dead zones across our commercial building. Highly recommended.', 'حلول التغطية الداخلية أزالت المناطق الميتة في مبنانا التجاري. نوصي بها بشدة.', NULL, '', true, 3, '2026-06-05 11:01:42.371'::timestamp(3), '2026-06-05 11:01:42.371'::timestamp(3));
INSERT INTO "Testimonial" ("id", "name", "location", "rating", "contentEn", "contentAr", "videoUrl", "imageUrl", "isPublished", "sortOrder", "createdAt", "updatedAt") VALUES ('cmq0tdrvn000whf64gu8fbryj', 'Omar Farouk', 'Ajman, UAE', 5, 'IoT integration helped us automate facility management and reduce operational costs significantly.', 'تكامل إنترنت الأشياء ساعدنا على أتمتة إدارة المرافق وتقليل التكاليف التشغيلية بشكل كبير.', NULL, '', true, 4, '2026-06-05 11:01:42.372'::timestamp(3), '2026-06-05 11:01:42.372'::timestamp(3));
INSERT INTO "Testimonial" ("id", "name", "location", "rating", "contentEn", "contentAr", "videoUrl", "imageUrl", "isPublished", "sortOrder", "createdAt", "updatedAt") VALUES ('cmq0tdrvo000xhf6439atnifr', 'Lisa Chen', 'Dubai, UAE', 5, 'End-to-end project delivery from consultation to training. BRT''s team is knowledgeable and reliable.', 'تسليم مشروع متكامل من الاستشارة إلى التدريب. فريق BRT على دراية وموثوق.', NULL, '', true, 5, '2026-06-05 11:01:42.373'::timestamp(3), '2026-06-05 11:01:42.373'::timestamp(3));
